import './App.css';
import { useState, useRef, useEffect } from 'react';
import FileViewer from './components/FileViewer';
import FileExplorer from './components/FileExplorer';
import FileUploadPage from './components/FileUploadPage';
import Footer from './components/Footer';
import Navbar from './components/Navbar';
import { Box } from '@mui/material';

function App() {
  const [fileContent, setFileContent] = useState('');
  const [fileName, setFileName] = useState('');
  const [activePanel, setActivePanel] = useState('viewer');
  const [currentFolderId, setCurrentFolderId] = useState(null);
  // Navbar yüksekliği artık dinamik olarak useEffect ile alınmayabilir
  // Eğer Navbar yüksekliği sabitse, doğrudan CSS'e yazılabilir.
  // const [navbarHeight, setNavbarHeight] = useState(0); // Bu satır çıkarılabilir
  // const navbarRef = useRef(null); // Bu ref de çıkarılabilir

  const [leftPanelWidth, setLeftPanelWidth] = useState(300);

  const [isResizing, setIsResizing] = useState(false);
  const initialX = useRef(0);
  const initialPanelWidth = useRef(0);

  // Sürükleme ile ilgili useEffect kısmı aynı kalmalı
  useEffect(() => {
    if (isResizing) {
      document.body.style.cursor = 'ew-resize';

      const handleActualMouseMove = (e) => {
        const dx = e.clientX - initialX.current;
        const newWidth = Math.max(200, Math.min(600, initialPanelWidth.current + dx));
        setLeftPanelWidth(newWidth);
      };

      const handleActualMouseUp = () => {
        setIsResizing(false);
        document.body.style.cursor = 'default';
      };

      document.addEventListener('mousemove', handleActualMouseMove);
      document.addEventListener('mouseup', handleActualMouseUp);

      return () => {
        document.removeEventListener('mousemove', handleActualMouseMove);
        document.removeEventListener('mouseup', handleActualMouseUp);
        if (isResizing) {
            document.body.style.cursor = 'default';
        }
      };
    } else {
      document.body.style.cursor = 'default';
    }
  }, [isResizing]);

  const handleOpenFileContent = (name, content) => {
    setFileName(name);
    setFileContent(content);
    setActivePanel('viewer');
  };

  const handleShowUpload = () => {
    setActivePanel('upload');
  };

  const handleSelectFolder = (folderId) => {
    setCurrentFolderId(folderId);
  };

  const handleMouseDown = (e) => {
    e.preventDefault();
    initialX.current = e.clientX;
    initialPanelWidth.current = leftPanelWidth;
    setIsResizing(true);
  };

  // Navbar yüksekliğini sabit bir değer olarak kabul edelim (örneğin 64px)
  const NAVBAR_HEIGHT = '64px'; // Material-UI AppBar için yaygın bir değer

  return (
    <Box sx={{ display: 'flex', flexDirection: 'column', height: '100vh' }}>
      {/* Navbar'ı doğrudan burada sabit konumlandırıyoruz */}
      <Box
        // ref={navbarRef} // Eğer yüksekliği dinamik olarak okumayacaksak bu ref'e gerek yok
        sx={{
          position: 'fixed', // Ekranın üstünde sabit kalmasını sağlar
          top: 0,
          left: 0,
          width: '100%',
          zIndex: 1000, // Diğer içeriklerin üzerine çıkmasını sağlar
          backgroundColor: '#1976d2', // Örnek arka plan rengi
          color: 'white', // Metin rengi
          minHeight: NAVBAR_HEIGHT, // Navbar'ın yüksekliği
          display: 'flex',
          alignItems: 'center',
          px: 2,
          boxShadow: 3,
        }}
      >
        <Navbar onShowUpload={handleShowUpload} />
      </Box>

      {/* Ana içerik (TreeView ve Sağ Panel) için Box */}
      {/* Navbar yüksekliği kadar üstten padding bırakıyoruz */}
      <Box
        sx={{
          display: 'flex',
          flexGrow: 1,
          paddingTop: NAVBAR_HEIGHT, // Navbar yüksekliği kadar üstten boşluk bırak
          position: 'relative',
          overflow: 'hidden',
          minHeight: `calc(100vh - ${NAVBAR_HEIGHT})`, // Toplam ekran yüksekliğinden navbar yüksekliğini çıkar
          backgroundColor: '#f0f0f0',
        }}
      >
        {/* Sol Bölme (FileExplorer) */}
        <Box
          sx={{
            width: `${leftPanelWidth}px`,
            borderRight: '1px solid #ddd',
            overflowY: 'auto',
            flexShrink: 0,
            minWidth: '200px',
            maxWidth: '600px',
          }}
        >
          <FileExplorer
            onOpenFileContent={handleOpenFileContent}
            onSelectFolder={handleSelectFolder}
          />
        </Box>

        {/* Bölücü Çizgi (Resizer) */}
        <Box
          onMouseDown={handleMouseDown}
          sx={{
            width: '8px',
            cursor: 'ew-resize',
            position: 'relative',
            zIndex: 1,
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'stretch',
            '&::after': {
              content: '""',
              display: 'block',
              width: '2px',
              backgroundColor: isResizing ? '#666' : '#ccc',
              height: '100%',
              borderRadius: '1px',
            },
            '&:hover::after': {
              backgroundColor: '#999',
            },
            userSelect: 'none',
            WebkitUserSelect: 'none',
            MozUserSelect: 'none',
            msUserSelect: 'none',
          }}
        />

        {/* Sağ Bölme (FileViewer/FileUploadPage) */}
        <Box
          sx={{
            flex: 1,
            p: 2,
            overflowY: 'auto',
            minWidth: `calc(100% - ${leftPanelWidth}px - 8px)`,
          }}
        >
          {activePanel === 'viewer' ? (
            <FileViewer fileName={fileName} content={fileContent} />
          ) : (
            <FileUploadPage folderId={currentFolderId} />
          )}
        </Box>
      </Box>

      <Footer />
    </Box>
  );
}

export default App;
